s8 = sample*383;
dir = s8*0.125*3.1415*0.5;
v = 0.0005;
t1 = 0;//value1*0.01;//t1*0.97 + value1*v;
d = 1;
xx = sin(dir+10*time)*(sample*d+t1);
yy = cos(dir+10*time)*(sample*d+t1);
zz = 0;//value2*0.05*sample;
v = 0.001;

w = 1-sample*0.00003*t6;//(sample*sin(time*0.3)*0.02-1);
s1 = sin(t2*w);
s2 = sin(t3*w);
s3 = sin(t4*w);
c1 = cos(t2*w);
c2 = cos(t3*w);
c3 = cos(t4*w);

z = (c3*s1*c2 + s3*s2)*xx - (c3*s1*s2-s3*c2)*yy + c3*c1*zz;
x1 = (c1*c2*xx + c1*s2*yy - s1*zz);
y1 = ((s3*s1*c2 - c3*s2)*xx + (s3*s1*s2+c3*c2)*yy + s3*c1*zz);

a = 1.5;
zoom = 0.5*(1/(z+a));
x = 0.5 + zoom*x1;
y = 0.5 + zoom*y1;

pi3 = 3.1415*2*0.3333;
t = t5+sample*1.5;
c = 2/(z+1);
r = sin(t)*c;
r = if(above(r,1),1,r);
r = if(below(r,0),0,r);

g = sin(t+pi3)*c;
g = if(above(g,1),1,g);
g = if(below(g,0),0,g);

b = sin(t-pi3)*c;
b = if(above(b,1),1,b);
b = if(below(b,0),0,b);

